class Solution:
    def partitionArray(self, nums, k):
        s = sorted(nums)
        groups = 0
        i = 0
        n = len(s)
        while i < n:
            anchor = s[i]
            groups += 1
            while i < n and s[i] - anchor <= k:
                i += 1
        return groups

