var partitionArray = function(nums, k) {
    nums = nums.slice().sort((a, b) => a - b);
    let count = 1;
    let anchor = nums[0];
    for (const v of nums) {
        if (v - anchor > k) {
            count++;
            anchor = v;
        }
    }
    return count;
};
